import React, { useState, useEffect } from 'react';
import useGetDate from '../Hooks/useGetDate';
import { BASE_API_URL } from '../utils/constants';
import NasaObj from '../NasaObj';
import Info from '../Info';

const Single = () => {

  const [apod, setApod] = useState(null);
  const [err, setErr] = useState(null);
  const [todaysDate, setTodaysDate] = useState(null);
  const [userDate, setUserDate] = useState(null);
  const [loading, setLoading] = useState('');

  useEffect(() => {
    const singleDay = localStorage.getItem('singleDay');

    if (singleDay) {
      // setting the max date
      let date = new Date();
      const today = useGetDate(date);
      setTodaysDate(today);
      // retrieving the previously set single day
      const obj = JSON.parse(singleDay);
      setUserDate(obj.date);
      setApod(obj);
    } else {
      let date = new Date();
      const today = useGetDate(date);
      setTodaysDate(today);
      setUserDate(today);
    }

  }, []);

  const handleDate = (e) => {
    e.preventDefault();
    setLoading('Loading...');
    getPhoto(userDate);
  }

  const getPhoto = (date) => {
    setLoading('Loading...');
    fetch(`${BASE_API_URL}/api/single-img?date=${date}`, {
      method: 'GET'
    })
    .then(response => response.json())
    .then(data => {
      // if a status code other than 200 is sent back
      if (data.error) {
        setLoading('');
        setApod(null);
        setErr(data);
      } else {
        setLoading('');
        setApod(data);
        setErr(null);
        localStorage.setItem('singleDay', JSON.stringify(data));
      }
    })
    .catch(error => {
      console.log(error);
    });
  };

  return (
    <div className='single-div'>
      <header className='single-header'>
        <h1>Single APOD</h1>
        <p>Select a single date or scroll with the buttons</p>
      </header>
      <div className="single-form-wrap">
        <form>
          <div className="start-container">
            <label htmlFor="single-date">Your date 
            (earliest date: 06-16-1995): </label>
            <input type="date" id="single-date" name="single-date" min="1995-06-16" max={todaysDate} value=  {userDate ? userDate : todaysDate} onChange={(e) => setUserDate(e.target.value)}/>
          </div>   

          <button className="update-btn" onClick={handleDate}>Update picture</button>
        </form>
      </div>
      <div className="ui-text">{err 
        ? <div className="error-text">{err}</div> 
        : <div className="loading-text">{loading}</div>
      }
      </div>

      <div className="single-banner">
        <h2>{apod ? apod.title : 'Choose an image'}</h2>
        <p>{apod && apod.date}</p>
      </div>

      {apod ? <NasaObj apod={apod} /> : <div className='loader'>Loading...</div>}

      <div className="single-nav">
        <button className="previous-day" aria-label='go back a day'>
          <FontAwesomeIcon icon="fa-solid fa-chevron-right" />
          Previous
        </button>
        <button className="next-day" aria-label='go forward a day'>
          <FontAwesomeIcon icon="fa-solid fa-chevron-right" />
          Next
        </button>
      </div>

      {apod && <Info apod={apod} />}
    </div>
  )
}

export default Single
